import{_ as e,o as a,c as l,a3 as r}from"./chunks/framework.BTFg6ESq.js";const x=JSON.parse('{"title":"AI 模型元数据配置","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/settings/model-metadata.md","filePath":"user-guide/settings/model-metadata.md","lastUpdated":1778241999000}'),o={name:"user-guide/settings/model-metadata.md"};function d(n,t,i,s,g,h){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="ai-模型元数据配置" tabindex="-1">AI 模型元数据配置 <a class="header-anchor" href="#ai-模型元数据配置" aria-label="Permalink to &quot;AI 模型元数据配置&quot;">​</a></h1><blockquote><p>这个子面板用于控制<strong>模型在 UI 中的图标和分组显示</strong>。系统通过规则匹配自动为模型分配图标，帮助你区分不同提供商的各种模型家族。</p></blockquote><hr><h2 id="入口" tabindex="-1">入口 <a class="header-anchor" href="#入口" aria-label="Permalink to &quot;入口&quot;">​</a></h2><ol><li>点击标题栏右侧的 ⚙️ 图标进入设置。</li><li>在左侧导航栏中选择 <strong>AI 模型元数据配置</strong>。</li></ol><hr><h2 id="规则匹配逻辑" tabindex="-1">规则匹配逻辑 <a class="header-anchor" href="#规则匹配逻辑" aria-label="Permalink to &quot;规则匹配逻辑&quot;">​</a></h2><p>系统通过规则引擎自动为模型分配图标。规则按优先级排序，匹配成功后立即生效。</p><h3 id="规则匹配类型" tabindex="-1">规则匹配类型 <a class="header-anchor" href="#规则匹配类型" aria-label="Permalink to &quot;规则匹配类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">匹配方式</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Provider</strong></td><td style="text-align:left;">匹配服务提供商名称</td><td style="text-align:left;"><code>openai</code></td></tr><tr><td style="text-align:left;"><strong>Model</strong></td><td style="text-align:left;">精确匹配模型 ID</td><td style="text-align:left;"><code>gpt-4o</code></td></tr><tr><td style="text-align:left;"><strong>Prefix</strong></td><td style="text-align:left;">匹配模型 ID 前缀</td><td style="text-align:left;"><code>gpt-</code></td></tr><tr><td style="text-align:left;"><strong>Group</strong></td><td style="text-align:left;">匹配分组名称</td><td style="text-align:left;"><code>chat</code></td></tr></tbody></table><p>支持<strong>正则表达式</strong>。</p><hr><h2 id="操作界面" tabindex="-1">操作界面 <a class="header-anchor" href="#操作界面" aria-label="Permalink to &quot;操作界面&quot;">​</a></h2><h3 id="视图与过滤" tabindex="-1">视图与过滤 <a class="header-anchor" href="#视图与过滤" aria-label="Permalink to &quot;视图与过滤&quot;">​</a></h3><ul><li><strong>网格/列表</strong> 双视图切换。</li><li><strong>搜索过滤</strong>：按关键字（匹配值、类型、分组、描述）、启用状态搜索。</li><li><strong>排序</strong>：按优先级、类型、名称、创建时间。</li><li><strong>分页</strong>：管理大量规则时保持界面清晰。</li></ul><h3 id="常用操作" tabindex="-1">常用操作 <a class="header-anchor" href="#常用操作" aria-label="Permalink to &quot;常用操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">操作</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>添加规则</strong></td><td style="text-align:left;">选择匹配类型，输入匹配值，选择预设图标</td></tr><tr><td style="text-align:left;"><strong>编辑/删除</strong></td><td style="text-align:left;">修改已有规则</td></tr><tr><td style="text-align:left;"><strong>启用/禁用</strong></td><td style="text-align:left;">临时关闭某条规则而不删除</td></tr><tr><td style="text-align:left;"><strong>重置为默认</strong></td><td style="text-align:left;">恢复内置规则</td></tr><tr><td style="text-align:left;"><strong>合并最新内置规则</strong></td><td style="text-align:left;">在应用更新后，合并新版内置规则</td></tr><tr><td style="text-align:left;"><strong>导入/导出 JSON</strong></td><td style="text-align:left;">批量管理规则集</td></tr></tbody></table><hr><h2 id="测试模式" tabindex="-1">测试模式 <a class="header-anchor" href="#测试模式" aria-label="Permalink to &quot;测试模式&quot;">​</a></h2><p>在测试模式下，输入<strong>模型 ID + Provider</strong>，系统会实时展示：</p><ul><li>匹配状态和命中的规则</li><li>匹配到的图标预览</li><li>候选规则列表（用于调试未匹配的情况）</li></ul><p>这在你新增模型后想确认图标是否正确时非常有用。</p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-模型元数据规则的作用是什么" tabindex="-1">Q：模型元数据规则的作用是什么？ <a class="header-anchor" href="#q-模型元数据规则的作用是什么" aria-label="Permalink to &quot;Q：模型元数据规则的作用是什么？&quot;">​</a></h3><p>它控制模型在编辑器和对话框中的显示图标和分组，对于区分同一提供商的不同模型家族很有用（如分清 GPT-4o 和 o1 系列）。</p>',26)])])}const c=e(o,[["render",d]]);export{x as __pageData,c as default};
